import { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';  // Changed from Nav
import image4 from '../assets/image4.jpg';

function ContactPage() {
  const [theme, setTheme] = useState('dark');
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') || 'dark';
    setTheme(savedTheme);
    document.body.className = savedTheme === 'light' ? 'light-mode' : '';
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.body.className = newTheme === 'light' ? 'light-mode' : '';
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
    setSubmitted(true);
  };

  return (
    <>
      <Navbar theme={theme} toggleTheme={toggleTheme} />
      <main className="container">
        <section className="contact-section">
          <h2>Contact Me</h2>
          {submitted ? (
            <div className="success-message">
              <p>Thank you {formData.name}!</p>
              <p>We will get back to you soon.</p>
            </div>
          ) : (
            <form onSubmit={handleSubmit}>
              <div>
                <label htmlFor="name">Name:</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                />
              </div>
              
              <div>
                <label htmlFor="email">Email:</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
              </div>
              
              <div>
                <label htmlFor="message">Message:</label>
                <textarea
                  id="message"
                  name="message"
                  rows="5"
                  value={formData.message}
                  onChange={handleChange}
                  required
                />
              </div>
              
              <button type="submit">Submit</button>
            </form>
          )}
        </section>

        <section className="resources-section">
          <h2>Gaming Resources</h2>
          <table>
            <thead>
              <tr><th>Resource Name</th><th>Description</th></tr>
            </thead>
            <tbody>
              <tr><td>IGN</td><td>Gaming news and reviews</td></tr>
              <tr><td>Steam</td><td>Online gaming platform</td></tr>
              <tr><td>Discord</td><td>Gaming community communication</td></tr>
            </tbody>
          </table>
        </section>

        <section className="map-section">
          <h2>Map Location</h2>
          <img src={image4} alt="Map placeholder" />
        </section>

        <section className="links-section">
          <h2>External Links</h2>
          <a href="https://www.ign.com" target="_blank" rel="noopener noreferrer">IGN</a><br />
          <a href="https://store.steampowered.com" target="_blank" rel="noopener noreferrer">Steam</a><br />
          <a href="https://www.twitch.tv" target="_blank" rel="noopener noreferrer">Twitch</a>
        </section>

        <footer>
          <p>Email: gaming@email.com | © 2026 Gaming Passion</p>
        </footer>
      </main>
    </>
  );
}

export default ContactPage;
